window.__LIBQ=window.__LIBQ||{};window.__LIBQ["pham-nhan-tu-tien"]=window.__LIBQ["pham-nhan-tu-tien"]||{};window.__LIBQ["pham-nhan-tu-tien"]["q05"]=window.__LIBQ["pham-nhan-tu-tien"]["q05"]||{};window.__LIBQ["pham-nhan-tu-tien"]["q05"]["factions"]={"updatedAt":"2026-07-14","count":61,"factions":[{"id":"yem-nguyet-tong","name":"Yểm Nguyệt Tông","cn":"掩月宗","type":"tong-mon","typeLabel":"Tông môn","diaBan":"","nhanVatChinh":["Nam Cung Uyển"],"blurb":"Tông môn mà Nam Cung Uyển thuộc về, được nhắc tới khi Hàn Lập hồi tưởng về nàng.","detail":"Tông phái mà Nam Cung Uyển — nữ tử từng có duyên hợp thể với Hàn Lập — thuộc về. Được nhắc tới khi Hàn Lập đến Vô Biên Hải, trong lòng hồi tưởng nàng với tình cảm phức tạp.","nguon":["@c0593"]},{"id":"lac-van-tong","name":"Lạc Vân Tông","cn":"落云宗","type":"tong-mon","typeLabel":"Tông môn","diaBan":"Vân Mộng Sơn, Khê Quốc","nhanVatChinh":[],"blurb":"Một trong ba tông phái đứng đầu Khê Quốc, nổi tiếng về luyện đan thuật, liên hợp cùng Cổ Kiếm Viện và Bách Xảo Viện chiếm cứ Vân Mộng Sơn.","detail":"Đại phái tu tiên tại Khê Quốc, đặc biệt nổi danh về luyện đan thuật. Cùng Cổ Kiếm Viện và Bách Xảo Viện liên hợp chiếm cứ Vân Mộng Sơn — nơi có Linh Nhãn Chi Thụ. Đang trong kỳ thu nhận đệ tử, Hàn Lập giả thân phận Luyện Khí kỳ trà trộn vào.","nguonGoc":"Tông phái lâu đời tại Khê Quốc","tonChi":"Luyện đan thuật","quanHe":"Liên hợp với Cổ Kiếm Viện và Bách Xảo Viện chiếm cứ Vân Mộng Sơn","trangThai":"hưng","tabs":{"tienTrinh":[{"chuong":"@c0594","loai":"nhắc tới","importance":"major","giaiDoan":"Xuất hiện, Hàn Lập trà trộn","text":"Lạc Vân Tông đang thu nhận đệ tử, Hàn Lập giả thân phận Luyện Khí kỳ trà trộn vào với mục đích tiếp cận tông phái nổi tiếng luyện đan thuật.","trangThaiMoc":"hưng","anchor":"tu tiên đại phái “Lạc Vân Tông” nơi đây thu nhận đệ tử"}]},"nguon":["@c0594"]},{"id":"co-kiem-vien","name":"Cổ Kiếm Viện","type":"tong-mon","typeLabel":"Tông môn","diaBan":"Vân Mộng Sơn, Khê Quốc","nhanVatChinh":[],"blurb":"Một trong ba tông phái đứng đầu Khê Quốc, liên hợp chiếm cứ Vân Mộng Sơn.","detail":"Tông phái tu tiên tại Khê Quốc, cùng Lạc Vân Tông và Bách Xảo Viện liên hợp chiếm cứ Vân Mộng Sơn.","quanHe":"Liên hợp với Lạc Vân Tông và Bách Xảo Viện chiếm cứ Vân Mộng Sơn","trangThai":"hưng","tabs":{"tienTrinh":[{"chuong":"@c0594","loai":"nhắc tới","importance":"normal","giaiDoan":"Xuất hiện","text":"Được giới thiệu là một trong ba tông phái chiếm cứ Vân Mộng Sơn.","anchor":"do “Cổ Kiếm Viện” “Lạc Vân Tông” “Bách Xảo Viện” ba cái tông phái liên hợp chiếm cứ"}]},"nguon":["@c0594"]},{"id":"bach-xao-vien","name":"Bách Xảo Viện","type":"tong-mon","typeLabel":"Tông môn","diaBan":"Vân Mộng Sơn, Khê Quốc","nhanVatChinh":["Phó lão giả","Thạch lão giả","Xương Chánh trưởng lão","Đại hán đầu hói"],"blurb":"Một trong ba tông phái đứng đầu Khê Quốc, liên hợp chiếm cứ Vân Mộng Sơn.","detail":"Tông phái tu tiên tại Khê Quốc, cùng Cổ Kiếm Viện và Lạc Vân Tông liên hợp chiếm cứ Vân Mộng Sơn.","quanHe":"Liên hợp với Cổ Kiếm Viện và Lạc Vân Tông chiếm cứ Vân Mộng Sơn","trangThai":"hoat-dong","tabs":{"tienTrinh":[{"chuong":"@c0594","loai":"nhắc tới","importance":"normal","giaiDoan":"Xuất hiện","text":"Được giới thiệu là một trong ba tông phái chiếm cứ Vân Mộng Sơn.","anchor":"do “Cổ Kiếm Viện” “Lạc Vân Tông” “Bách Xảo Viện” ba cái tông phái liên hợp chiếm cứ"},{"chuong":"@c0615","loai":"nhắc tới","importance":"normal","giaiDoan":"Tiết lộ thông tin cơ bản","trangThaiMoc":"hoat-dong","text":"Được nhắc đến là một trong ba phái Vân Mộng Sơn tham gia Thí Kiếm Đại Hội, cùng Lạc Vân Tông chưa từng đoạt quán quân.","anchor":"Đệ tử chúng ta cùng Bách Xảo Viện chỉ có thể đứng ngoài"},{"chuong":"@c0618","loai":"nhắc tới","importance":"normal","giaiDoan":"Được nhắc tới trong thông báo Thí Kiếm đại hội","text":"Cổ Kiếm Môn gửi thông hàm, Thí Kiếm đại hội nửa năm sau tổ chức tại Bách Xảo Viện ở Vân Mông Tây Mạch, ba phái mỗi bên 30 đệ tử.","anchor":"lần này, địa điểm tổ chức sẽ là Bách Xảo Viện"},{"chuong":"@c0624","loai":"xuat-hien","importance":"major","giaiDoan":"Đăng cai Thí Kiếm Đại Hội","trangThaiMoc":"đăng cai","text":"Bách Xảo Viện đăng cai Thí Kiếm Đại Hội ba phái, nghênh đón Cổ Kiếm Môn và Lạc Vân Tông.","anchor":"Bách Xảo Viện đón tiếp hai phái xong thì dẫn Cổ Kiếm Môn và Lạc Vân Tông nghỉ tại hai trạch viện lớn một ngày"}]},"nguon":["@c0594","@c0615","@c0618","@c0624"],"cn":"百巧院","thanhVien":[{"ten":"Phó lão giả","chucVu":"Viện chủ","tuChuong":"@c0624","trangThai":"dang-hoat-dong"},{"ten":"Thạch lão giả","chucVu":"Kết Đan tu sĩ","tuChuong":"@c0624","trangThai":"dang-hoat-dong"},{"ten":"Xương Chánh trưởng lão","chucVu":"Trưởng lão","tuChuong":"@c0624","trangThai":"xuat-ngoai"},{"ten":"Đại hán đầu hói","chucVu":"Trọng tài Thí Kiếm Đại Hội","tuChuong":"@c0624","trangThai":"dang-hoat-dong"}]},{"id":"thien-dao-minh","name":"Thiên Đạo Minh","cn":"天道盟","type":"lien-minh","typeLabel":"Liên minh","diaBan":"Khê quốc và hai quốc gia lân cận","nhanVatChinh":["Đồng tử họ Lam"],"blurb":"Liên minh lỏng lẻo do tu sĩ hơn mười quốc gia thành lập để đối chọi chính đạo và ma đạo. Cổ Kiếm Môn, Lạc Vân Tông, Bách Xảo là trung tâm thế lực này.","detail":"Thành lập sau khi Hàn Lập rời Thiên Nam, Thiên Đạo Minh là liên minh lỏng lẻo của tu sĩ hơn mười quốc gia nhằm đối trọng với chính đạo và ma đạo. Khê quốc cùng hai quốc gia lân cận thuộc phạm vi của Thiên Đạo Minh, trong đó Cổ Kiếm Môn, Lạc Vân Tông và Bách Xảo chính là nòng cốt. Thiên Đạo Minh cùng chính đạo, ma đạo đạt trạng thái cân bằng xảo diệu, không bên nào dám gây sự lớn.","nguonGoc":"Thành lập sau khi Hàn Lập rời Thiên Nam, do tu sĩ hơn mười quốc gia liên minh","quyMo":"Hơn mười quốc gia","quanHe":"Đối trọng chính đạo và ma đạo; thành viên hiệp nghị bốn thế lực chống Mạc Lan","trangThai":"Đang hoạt động","capNhatToi":"@c0595","thanhVien":[{"ten":"Cổ Kiếm Môn","chucVu":"trung tâm thế lực","tuChuong":"@c0595","trangThai":"dang-hoat-dong"},{"ten":"Lạc Vân Tông","chucVu":"trung tâm thế lực","tuChuong":"@c0595","trangThai":"dang-hoat-dong"},{"ten":"Bách Xảo","chucVu":"trung tâm thế lực","tuChuong":"@c0595","trangThai":"dang-hoat-dong"}],"tabs":{"tienTrinh":[{"chuong":"@c0595","loai":"lap","importance":"major","giaiDoan":"Thành lập và cân bằng thế lực","text":"Liên minh lỏng lẻo hơn mười quốc gia thành lập để đối chọi chính đạo và ma đạo. Cổ Kiếm Môn, Lạc Vân Tông, Bách Xảo là trung tâm. Cùng ba thế lực còn lại đạt cân bằng xảo diệu tại Thiên Nam.","anchor":"do tu sĩ của mười mấy quốc gia liên minh lại thành lập lực lượng để đối chọi với hai tổ chức ma giáo và chính giáo"}]},"nguon":["@c0595","@c0631","@c0671"]},{"id":"cuu-quoc-minh","name":"Cửu Quốc Minh","cn":"九国盟","type":"lien-minh","typeLabel":"Liên minh","diaBan":"Biên giới Thiên Nam giáp Mạc Lan","nhanVatChinh":[],"blurb":"Liên minh gồm bảy phái Việt Quốc cùng nhiều tông phái nhỏ và tán tu, làm chủ tuyến phòng ngự chống Mạc Lan bộ lạc.","detail":"Cửu Quốc Minh phát triển từ bảy phái Việt Quốc, thu nạp thêm nhiều tông phái nhỏ và tán tu bị chính đạo, ma đạo xua đuổi. Bị Mạc Lan bộ lạc (có tiếp viện từ Mạc Lan đệ nhị và đệ tứ) áp đảo, mất một số lãnh thổ. Phát tín hiệu cầu cứu kèm uy hiếp ba thế lực còn lại: nếu không tham chiến thì bỏ mặc Mạc Lan tự do tiến vào. Sau đại chiến quyết định với hơn ngàn tu sĩ tử trận mới chặn được. Đạt hiệp nghị bốn thế lực: Cửu Quốc Minh làm chủ chống Mạc Lan, ba nhà thay phiên trợ giúp.","nguonGoc":"Phát triển từ bảy phái Việt Quốc, thu nạp tông phái nhỏ và tán tu","quyMo":"Bảy phái Việt Quốc + nhiều tông phái nhỏ + tán tu","quanHe":"Làm chủ hiệp nghị bốn thế lực chống Mạc Lan; ba thế lực còn lại thay phiên trợ giúp","trangThai":"Đang hoạt động, nắm quyền tổ chức Giao dịch hội","capNhatToi":"@c0595","tabs":{"tienTrinh":[{"chuong":"@c0595","loai":"khai-chien","importance":"major","giaiDoan":"Đại chiến với Mạc Lan và hiệp nghị bốn thế lực","trangThaiMoc":"bị áp đảo → ổn định","text":"Bị Mạc Lan bộ lạc (có tiếp viện từ đệ nhị, đệ tứ) áp đảo, mất lãnh thổ. Phát tín hiệu cầu cứu kèm uy hiếp ba thế lực. Sau đại chiến quyết định hơn ngàn tu sĩ tử trận mới chặn được Mạc Lan. Đạt hiệp nghị: Cửu Quốc Minh làm chủ, ba nhà thay phiên trợ giúp.","anchor":"Cửu Quốc Minh phát ra tín hiệu cầu cứu các thế lực còn lại đồng thời uy hiếp"},{"chuong":"@c0671","loai":"nhắc tới","importance":"normal","giaiDoan":"Nắm quyền tổ chức Giao dịch hội","text":"Lữ Lạc kể cho Hàn Lập: Cửu Quốc Minh giành được quyền tổ chức Giao dịch hội từ hai phái Chính tà sau khi chính tà khuếch trương.","anchor":"quyền này thuộc về Cửu Quốc Minh, hai phái chính tà cũng chỉ biết ngậm bồ hòn làm ngọt"},{"chuong":"@c0674","loai":"nhắc tới","importance":"normal","giaiDoan":"Quản lý Điền Thiên Thành","text":"Thế lực xây dựng và quản lý Điền Thiên Thành, có tu sĩ chấp pháp canh gác và cấm chế cấm phi hành.","anchor":"Đây chính là do Cửu Quốc Minh trước sau mấy lần xây dựng bổ sung thêm mới có được quy mô như vậy"}]},"nguon":["@c0595","@c0671","@c0674"]},{"id":"mac-lan-bo-lac","name":"Mạc Lan bộ lạc","cn":"莫兰部落","type":"bo-lac","typeLabel":"Bộ lạc","diaBan":"Biên giới Thiên Nam","nhanVatChinh":[],"blurb":"Bộ lạc pháp sĩ đối đầu Cửu Quốc Minh tại biên giới Thiên Nam, nhận tiếp viện từ Mạc Lan đệ nhị và đệ tứ khiến lực lượng tăng gấp bội.","detail":"Mạc Lan bộ lạc giằng co lâu dài với Cửu Quốc Minh, bỗng nhận được tiếp viện từ Mạc Lan đệ nhị và Mạc Lan đệ tứ, pháp sĩ tăng gấp bội. Áp đảo Cửu Quốc Minh, cướp một số lãnh thổ, trước khi bị chặn lại trong đại chiến quyết định có hơn ngàn tu sĩ tử trận.","quyMo":"Pháp sĩ tăng gấp bội sau tiếp viện","trangThai":"bị chặn, đang giằng co","capNhatToi":"@c0595","tabs":{"tienTrinh":[{"chuong":"@c0595","loai":"khai-chien","importance":"major","giaiDoan":"Tiếp viện và đại chiến với Cửu Quốc Minh","trangThaiMoc":"tăng cường → bị chặn","text":"Nhận tiếp viện từ Mạc Lan đệ nhị và đệ tứ, pháp sĩ tăng gấp bội. Áp đảo Cửu Quốc Minh, cướp lãnh thổ. Bị chặn lại sau đại chiến quyết định.","anchor":"Mạc Lan bộ lạc giằng co đã lâu với Cửu Quốc Minh bỗng nhiên nhận được tiếp viện đến từ các tộc Mạc Lan đệ nhị và Mạc Lan đệ tứ"}]},"nguon":["@c0595"]},{"id":"co-kiem-mon","name":"Cổ Kiếm Môn","cn":"古剑门","type":"tong-mon","typeLabel":"Tông môn","diaBan":"Vân Mộng Sơn (vị trí chính), Khê Quốc","nhanVatChinh":["Khương Vân","Thanh bào nho sinh","Bạch y thiếu phụ","Diêu Phong"],"blurb":"Một trong ba phái lớn tại Vân Mộng Sơn, am hiểu ngự kiếm thuật, có tuyệt học Thái Bạch Kiếm Quyết, thực lực cường đại nhất trong ba phái.","detail":"Tông môn am hiểu ngự kiếm thuật, chiếm cứ vị trí chính tại Vân Mộng Sơn, Khê Quốc. Sở hữu tuyệt học trấn phái Thái Bạch Kiếm Quyết, đệ tử tu vi đại thành nhờ tính công kích siêu cường mà cùng cấp ít đối thủ. Thực lực cường đại nhất trong ba phái nhưng yêu cầu linh căn cực cao, có thu tán tu song đệ tử ít nhất trong ba.","nguonGoc":"Không rõ","tonChi":"Chuyên ngự kiếm thuật","quyMo":"Ít đệ tử nhất trong ba phái do yêu cầu linh căn cao","tabs":{"tienTrinh":[{"chuong":"@c0596","loai":"nhắc tới","importance":"normal","giaiDoan":"Hàn Lập cân nhắc gia nhập","text":"Hàn Lập phân tích Cổ Kiếm Môn: thực lực mạnh nhất ba phái, có Thái Bạch Kiếm Quyết nhưng yêu cầu linh căn quá cao nên bỏ qua.","anchor":"đệ tử Cổ Kiếm Môn một khi tu vi đại thành, bằng vào tính công kích siêu cường, các tu sĩ cùng cấp thường không phải là đối thủ"},{"chuong":"@c0615","loai":"nhắc tới","importance":"major","giaiDoan":"Tiết lộ thông tin cơ bản","trangThaiMoc":"hoat-dong","text":"Được Vương sư huynh giới thiệu là một trong ba phái Vân Mộng Sơn, môn phái kiếm tu với công pháp và kiếm khí lợi hại phi thường, luôn đoạt quán quân Thí Kiếm Đại Hội để chiếm phần lớn thuần dịch Linh Nhãn Chi Thụ.","anchor":"môn phái kiếm tu Cổ Kiếm Môn người ta, vô luận là công pháp hay kiếm khí đều lợi hại phi thường"},{"chuong":"@c0624","loai":"xuat-hien","importance":"major","giaiDoan":"Tham gia Thí Kiếm Đại Hội","trangThaiMoc":"tham dự","text":"Cổ Kiếm Môn đến Bách Xảo Viện bằng kiếm khí phi hành dự Thí Kiếm Đại Hội. Diêu Phong thua trận đầu trước Hàn Lập.","anchor":"Là Cổ Kiếm Môn, bọn họ chính là sử dụng kiếm khí phi hành"}]},"nguon":["@c0596","@c0615","@c0624"],"trangThai":"hoat-dong","thanhVien":[{"ten":"Khương Vân","chucVu":"Trưởng đoàn (Kết Đan)","tuChuong":"@c0624","trangThai":"dang-hoat-dong"},{"ten":"Thanh bào nho sinh","chucVu":"Kết Đan tu sĩ, Bạch Bích Song Kiếm","tuChuong":"@c0624","trangThai":"dang-hoat-dong"},{"ten":"Bạch y thiếu phụ","chucVu":"Kết Đan tu sĩ, Bạch Bích Song Kiếm","tuChuong":"@c0624","trangThai":"dang-hoat-dong"},{"ten":"Diêu Phong","chucVu":"Đệ tử Trúc Cơ sơ kỳ","tuChuong":"@c0624","trangThai":"thua-tran"}]},{"id":"an-kiem-phong","name":"Ẩn Kiếm Phong","cn":"隐剑峰","type":"phan-nhanh","typeLabel":"Phân nhánh thế lực","diaBan":"Lạc Vân Tông","nhanVatChinh":["Lão giả tóc xám trắng"],"blurb":"Một trong lục Phong của Lạc Vân Tông, chủ tu công pháp kim thuộc tính. Lần thu đệ tử trước chỉ nhận hai người nhưng đều có hai linh căn.","detail":"Ẩn Kiếm Phong chuyên về công pháp kim thuộc tính trong Lạc Vân Tông. Đại diện là lão giả tóc xám trắng, đã tranh đệ tử có Đoán kim chi thể nhưng không thành, chưởng môn phân đệ tử đó về Huyễn Thạch Phong.","nguonGoc":"Thuộc Lạc Vân Tông","tonChi":"Chủ tu công pháp kim thuộc tính","tabs":{"tienTrinh":[{"chuong":"@c0599","loai":"nhắc tới","importance":"normal","giaiDoan":"Tranh đệ tử Đoán kim chi thể","text":"Đại diện Ẩn Kiếm Phong tranh đệ tử có Đoán kim chi thể, viện lý phong chủ tu kim thuộc tính, nhưng chưởng môn quyết định phân đệ tử đó về Huyễn Thạch Phong.","anchor":"ta chỉ muốn có được tên đệ tử có Đoán kim chi thể để Ẩn Kiếm Phong chúng ta dạy dỗ"}]},"nguon":["@c0599"]},{"id":"hoa-van-phong","name":"Hỏa Vân Phong","cn":"火云峰","type":"phan-nhanh","typeLabel":"Phân nhánh thế lực","diaBan":"Lạc Vân Tông","nhanVatChinh":["Trung niên sắc mặt trắng","Lý sư bá"],"blurb":"Một trong lục Phong của Lạc Vân Tông, lấy hỏa thuộc tính công pháp làm chính, nhưng cũng có Lý sư bá tu Kim Luyện quyết nổi danh.","detail":"Hỏa Vân Phong chuyên hỏa thuộc tính công pháp, tuy nhiên cũng có Lý sư bá tu Kim Luyện quyết nổi danh ở Khê Quốc. Đại diện trung niên sắc mặt trắng tranh đệ tử Đoán kim chi thể nhưng không thành.","nguonGoc":"Thuộc Lạc Vân Tông","tonChi":"Hỏa thuộc tính công pháp là chính","thanhVien":[{"ten":"Lý sư bá","chucVu":"Sư bá","tuChuong":"@c0599","trangThai":"dang-hoat-dong"}],"tabs":{"tienTrinh":[{"chuong":"@c0599","loai":"nhắc tới","importance":"normal","giaiDoan":"Tranh đệ tử Đoán kim chi thể","text":"Đại diện Hỏa Vân Phong viện dẫn Lý sư bá với Kim Luyện quyết nổi danh ở Khê Quốc để tranh đệ tử Đoán kim chi thể, nhưng chưởng môn phân về Huyễn Thạch Phong.","anchor":"Hỏa Vân Phong chúng ta cũng có Lý sư bá với Kim Luyện quyết ở Khê Quốc này cũng rất là nổi danh"}]},"nguon":["@c0599"]},{"id":"huyen-thach-phong","name":"Huyễn Thạch Phong","cn":"幻石峰","type":"phan-nhanh","typeLabel":"Phân nhánh thế lực","diaBan":"Lạc Vân Tông","nhanVatChinh":[],"blurb":"Một trong lục Phong của Lạc Vân Tông. Thanh niên có Đoán kim chi thể được chưởng môn phân về đây.","detail":"Huyễn Thạch Phong là một trong lục Phong của Lạc Vân Tông, được chưởng môn Ngụy Nhất Minh chọn làm nơi tiếp nhận đệ tử có Đoán kim chi thể khi Ẩn Kiếm Phong và Hỏa Vân Phong tranh chấp không phân thắng bại.","nguon":["@c0599"]},{"id":"thien-tuyen-phong","name":"Thiên Tuyền Phong","cn":"天泉峰","type":"chi-phong","typeLabel":"Chi phong","diaBan":"Tuyền Phong Sơn","nhanVatChinh":["Sư tổ (trung niên nho sinh, Kết Đan trung kỳ)","Du Quân","Tam sư huynh (bạch phát lão giả)","Mộ Phái Linh","Mã sư muội","Tân sư đệ"],"blurb":"Một ngọn phong do vị trung niên nho sinh tu vi Kết Đan trung kỳ làm chủ, có các đệ tử tinh thông chế phù thuật và luyện đan dược, đồng thời thu nhận ngoại môn đệ tử mới.","detail":"Thiên Tuyền Phong tọa lạc trên Tuyền Phong Sơn, có dãy lầu các và sương phòng u tĩnh nơi sư tổ cư ngụ. Sư tổ là tu sĩ Kết Đan trung kỳ, tướng mạo cổ quái, ba chòm râu đen, trang phục nho sinh. Dưới quyền có Du Quân, tam sư huynh (bạch phát lão giả gần sáu mươi, tinh thông chế phù thuật) và Mộ Phái Linh (ngũ sư tỷ, Trúc Cơ trung kỳ, am hiểu luyện đan dược). Ngoài ra còn Mã sư muội và Tân sư đệ — hậu bối tục giới của sư tổ, chưa chính thức được thu nhận nhưng chỉ là sớm muộn, có bối phận đặc biệt cao. Thiên Tuyền Phong nhận ngoại môn đệ tử mới gồm Hàn Lập (phân cho Mộ Phái Linh, trông coi dược viên) và Đỗ Đông (phân cho tam sư huynh, phụ giúp chế phù). Phía sau động phủ Mộ Phái Linh có dược viên rộng hơn trăm trượng với vài loại dược thảo, ba tòa nhà tranh và một ngọn núi nhỏ.","nguon":["@c0600"]},{"id":"ngan-nguyet-lang-toc","name":"Ngân Nguyệt lang tộc","cn":"银月狼族","type":"yeu-toc","typeLabel":"Yêu tộc","diaBan":"Không rõ","nhanVatChinh":["Ngân Nguyệt"],"blurb":"Tộc yêu thú mà Ngân Nguyệt tự nhận là thành viên dựa trên ký ức kiếp trước tàn khuyết. Sở hữu thiên phú thôn phệ linh hồn.","detail":"Ngân Nguyệt tự xưng là thành viên Ngân Nguyệt lang tộc, tên do cô tự đặt dựa trên ký ức tàn khuyết. Hàn Lập cho biết chưa từng thấy loài yêu thú này trong điển tịch, Ngân Nguyệt cũng thừa nhận có thể nhớ lầm. Tộc này sở hữu thiên phú thôn phệ linh hồn và thiên sinh khắc chế Tứ đồng linh hồ.","nguonGoc":"Không rõ, có thể là giống loài cổ xưa hoặc đã tuyệt chủng","dacDiem":"Thiên phú thôn phệ linh hồn, thiên sinh khắc chế Tứ đồng linh hồ","thanhVien":[{"ten":"Ngân Nguyệt","chucVu":"Thành viên (ký ức tàn khuyết)","tuChuong":"@c0612","trangThai":"dang-hoat-dong"}],"tabs":{"tienTrinh":[{"chuong":"@c0612","loai":"nhắc tới","importance":"normal","giaiDoan":"Ngân Nguyệt tự thuật","trangThaiMoc":"Không rõ tình trạng hiện tại","text":"Ngân Nguyệt tự xưng là thành viên Ngân Nguyệt lang tộc dựa trên ký ức tàn khuyết kiếp trước. Hàn Lập cho biết chưa thấy trong điển tịch.","anchor":"Ta chưa thấy trong điển tịch có nói đến loài yêu thú này"}]},"nguon":["@c0612"]},{"id":"van-mong-son-tam-phai","name":"Tam phái Vân Mộng Sơn","cn":"","type":"lien-minh","typeLabel":"Liên minh tông phái","diaBan":"Vân Mộng Sơn","nhanVatChinh":[],"blurb":"Liên minh ba tông phái trên Vân Mộng Sơn, tổ chức Thí Kiếm Đại Hội và điều chế Minh Thanh Linh Thuỷ.","detail":"Liên minh của ba tông phái trên Vân Mộng Sơn (gồm Lạc Vân Tông, Cổ Kiếm Môn và một phái nữa). Định kỳ tổ chức Thí Kiếm Đại Hội cho đệ tử tỷ thí, phần thưởng gồm Định Linh Đan (quán quân) và Minh Thanh Linh Thuỷ (top mười). Tiền bối Kết Đan kỳ trong ba phái thường cấp pháp khí uy lực lớn cho con cháu đệ tử tham dự đại hội.","tabs":{"tienTrinh":[{"chuong":"@c0616","loai":"nhắc tới","importance":"normal","giaiDoan":"Tổ chức Thí Kiếm Đại Hội, triệu tập đệ tử","text":"Tam phái Vân Mộng Sơn điều chế Minh Thanh Linh Thuỷ làm phần thưởng top mười Thí Kiếm Đại Hội, tiền bối Kết Đan kỳ cấp pháp khí cho con cháu tham gia.","anchor":"tam phái Vân Mộng Sơn lại điều chế nó"}]},"capNhatToi":"@c0616","nguon":["@c0616"]},{"id":"bach-phuong-phong","name":"Bạch Phượng Phong","type":"tong-mon","typeLabel":"Phong (thuộc Hoàng Phong Cốc)","diaBan":"Vân Mộng Sơn","nhanVatChinh":["Kim Dung"],"blurb":"Một trong Lục Xảo Phong thuộc Hoàng Phong Cốc, hai vị Phong chủ đều là nữ tu sĩ Kết Đan kỳ, đệ tử lấy nữ làm chính, số lượng không đông.","detail":"Bạch Phượng Phong là thế lực đặc thù trong Lục Xảo Phong: cả hai Phong chủ đều là nữ tu sĩ Kết Đan kỳ, môn hạ đệ tử cũng chủ yếu là nữ. Trong tỷ thí Lục Xảo Phong chỉ có mười mấy nữ đệ tử trẻ tham gia, số lượng ít nhất trong các phong.","nguon":["@c0619"],"tabs":{"tienTrinh":[{"chuong":"@c0619","loai":"nhac-toi","importance":"normal","giaiDoan":"Tỷ thí Lục Xảo Phong","text":"Được giới thiệu là phong có hai Phong chủ nữ Kết Đan kỳ, đệ tử chủ yếu nữ, chỉ mười mấy người tham gia tỷ thí.","anchor":"Hai vị Phong chủ không những đều là nữ tu sĩ Kết đan kỳ mà môn hạ đệ tử cũng lấy nữ làm chính"}]}},{"id":"tuan-gia","name":"Tuân gia","type":"gia-toc","typeLabel":"Gia tộc tu tiên","diaBan":"Khê quốc","nhanVatChinh":["Tuân Thông"],"blurb":"Tu tiên gia tộc đỉnh đỉnh đại danh ở Khê quốc, sở hữu pháp khí Hoả Lãng châu nổi danh.","detail":"Gia tộc tu tiên nổi danh ở Khê quốc, Tuân sư đệ (Tuân Thông) xuất thân từ đây, được các trưởng bối toàn tâm dạy dỗ từ nhỏ. Gia tộc sở hữu pháp khí gia truyền Hoả Lãng châu.","nguon":["@c0620"]},{"id":"do-gia","name":"Đỗ gia","cn":"","type":"gia-toc","typeLabel":"Gia tộc tu tiên","diaBan":"","nhanVatChinh":["Đỗ Đông"],"blurb":"Gia tộc tu tiên bị tiêu diệt hai trăm năm trước, trấn tộc chi bảo là Hàn Nguyệt Luân. Đỗ Đông bị nghi là hậu nhân mai danh ẩn tích.","detail":"Gia tộc tu tiên đã bị tiêu diệt hai trăm năm trước. Trấn tộc chi bảo là Hàn Nguyệt Luân — đỉnh cấp pháp khí thuộc tính băng. Đỗ Đông hiện sở hữu Hàn Nguyệt Luân, bị các trưởng lão Lạc Vân Tông suy đoán là hậu nhân Đỗ gia mai danh ẩn tích, nay thấy an toàn mới xuất hiện.","trangThai":"da-diet","nguon":["@c0621","@c0623"]},{"id":"thuong-quan-gia-toc","name":"Thượng Quan gia tộc","cn":"","type":"gia-toc","typeLabel":"Gia tộc tu tiên","diaBan":"","nhanVatChinh":[],"blurb":"Gia tộc tu tiên có đệ tử trực hệ gia nhập Bách Xảo Viện, khi còn Luyện Khí Kỳ đã dùng pháp khí tự luyện chế đánh bại trưởng bối.","detail":"Gia tộc tu tiên, có đệ tử trực hệ gia nhập Bách Xảo Viện. Đệ tử này khi còn Luyện Khí Kỳ đã có thể dùng pháp khí do bản thân luyện chế đánh bại tu sĩ bậc trưởng bối.","nguon":["@c0621"]},{"id":"pho-gia","name":"Phó Gia","cn":"","type":"gia-toc","typeLabel":"Gia tộc","diaBan":"Không rõ","nhanVatChinh":[],"blurb":"Gia tộc giao tình không cạn với Đỗ Gia.","detail":"Được nhắc đến trong ngữ cảnh phân tích thân phận Đỗ Đông: Đỗ Gia giao tình không cạn với Phó Gia.","nguon":["@c0623"]},{"id":"hao-nhien-cac","name":"Hạo Nhiên Các","cn":"","type":"chinh-dao","typeLabel":"Chính đạo","diaBan":"","nhanVatChinh":["Nho sinh","Lão giả họ Mã"],"blurb":"Thế lực chính đạo, cài gián điệp (nho sinh họ Bạch) trà trộn Cổ Kiếm Môn hơn trăm năm, bị đồng tử Lam sư thúc lật tẩy.","detail":"Nho sinh họ Bạch là nhập môn đệ tử của Hạo Nhiên Các, trà trộn vào Cổ Kiếm Môn hơn trăm năm. Khi bị lộ, bạo phát nhắm bắt Mạnh Địch (Cửu Linh Kiếm Thể), cho thấy mục tiêu thực sự. Được đồng tử gọi là chính đạo Hạo Nhiên Các.","thanhVien":[{"ten":"Nho sinh","chucVu":"Nhập môn đệ tử (gián điệp)","tuChuong":"@c0627","trangThai":"bi-bat"},{"ten":"Lão giả họ Mã","chucVu":"Tu sĩ Nguyên Anh","tuChuong":"@c0725","trangThai":"hoat-dong"}],"tabs":{"tienTrinh":[{"chuong":"@c0627","loai":"nhắc tới","importance":"normal","giaiDoan":"Gián điệp bị lật tẩy","text":"Nho sinh họ Bạch bị đồng tử Lam sư thúc lật tẩy là nhập môn đệ tử Hạo Nhiên Các cài vào Cổ Kiếm Môn hơn trăm năm.","anchor":"thân là nhập môn đệ tử của chính đạo Hạo Nhiên Các các chủ"},{"chuong":"@c0725","loai":"nhắc tới","importance":"normal","giaiDoan":"Phái người chi viện","text":"Lão giả họ Mã thuộc Hạo Nhiên Các được phái đi cùng Hàn Lập trấn thủ biên giới Ngu Quốc.","anchor":"một lão giả họ Mã của Hạo Nhiên Các thuộc Chính Đạo Minh"}]},"nguon":["@c0627","@c0725"]},{"id":"thien-huyen-tong","name":"Thiên Huyễn Tông","cn":"天幻宗","type":"tong-mon","typeLabel":"Tông môn","diaBan":"","nhanVatChinh":["Bạch tu sĩ","Đỗ Đông"],"blurb":"Tông môn thuộc Ma đạo. Bạch tu sĩ tự xưng là đệ tử đích truyền, đã cài gian tế trà trộn vào Cổ Kiếm Môn trong Chánh đạo minh. Đỗ Đông cũng là đồng bọn, phối hợp tấn công từ bên trong.","detail":"Thiên Huyễn Tông là một tông môn thuộc Ma đạo. Bạch tu sĩ (trà trộn Cổ Kiếm Môn dưới danh nghĩa Bạch sư thúc) tự xưng đệ tử đích truyền. Đỗ Đông là đồng bọn, hai bên đã phối hợp từ trước: Đỗ Đông bảo chứng giúp Bạch tu sĩ thoát chết khi bị lão quái vật kiếm ti chế trụ. Đỗ Đông nhắc đến sư thúc và Tần tiền bối cần phối hợp ra tay, cho thấy còn nhiều nhân vật chưa lộ diện.","nguonGoc":"","tonChi":"","lanhDaoHienThoi":"","capBac":"","quyMo":"","trangThai":"hoat-dong","thanhVien":[{"ten":"Bạch tu sĩ","chucVu":"đệ tử đích truyền","tuChuong":"@c0629","trangThai":"hoat-dong"},{"ten":"Đỗ Đông","chucVu":"Thiếu chủ","tuChuong":"@c0629","trangThai":"dang-hoat-dong"}],"tabs":{"tienTrinh":[{"chuong":"@c0629","loai":"xuất hiện","importance":"major","giaiDoan":"Lộ diện trong Chánh đạo minh","text":"Bạch tu sĩ phá cửa tĩnh thất tự xưng đệ tử đích truyền Thiên Huyễn Tông, hé lộ đã cài gian tế vào Cổ Kiếm Môn. Phối hợp với Đỗ Đông và quân tấn công bên ngoài tạo thế đánh trong đánh ngoài.","anchor":"Đệ tử đích truyền của Ma đạo Thiên Huyễn Tông"},{"chuong":"@c0630","loai":"nhắc tới","importance":"major","giaiDoan":"Lộ diện qua Đỗ Đông","text":"Đỗ Đông lộ thân phận thiếu chủ Thiên Huyễn Tông, thi triển Đại La Thiên Huyễn Quyết trấn phái pháp quyết. Lão giả tóc rối nhắc Đỗ Đông không màng nguy hiểm mà tiến vào Lạc Vân Tông tạo điều kiện chánh tà hợp tác.","anchor":"nếu nói về ẩn nặc công pháp thì Thiên Huyễn Tông tại Thiên Nam nói là đệ nhị thì không ai dám nói là đệ nhất"}]},"nguon":["@c0629","@c0630"]},{"id":"ma-dao-luc-tong","name":"Ma Đạo Lục Tông","cn":"魔道六宗","type":"lien-minh","typeLabel":"Liên minh","diaBan":"","nhanVatChinh":[],"blurb":"Liên minh sáu tông phái Ma đạo. Bị Hồ sư huynh nghi ngờ là lực lượng tấn công quy mô lớn vào vị trí Chánh đạo minh đang canh giữ Linh Nhãn Chi Thụ, có cả tu sĩ Nguyên Anh Kỳ tham gia.","detail":"Hồ sư huynh nghi ngờ đám tu sĩ giấu mặt tấn công bên ngoài là người của Ma Đạo Lục Tông, vì sức mạnh quá lớn bao gồm cả Kết Đan Kỳ lẫn nghi có Nguyên Anh Kỳ tham gia.","trangThai":"hoat-dong","tabs":{"tienTrinh":[{"chuong":"@c0629","loai":"khai chiến","importance":"normal","giaiDoan":"Nghi tấn công vị trí Linh Nhãn Chi Thụ","text":"Bị nghi là lực lượng tấn công quy mô lớn vào vị trí Chánh đạo minh canh giữ Linh Nhãn Chi Thụ, gồm cả tu sĩ Nguyên Anh Kỳ.","anchor":"Xem ra không phải là Chánh đạo minh mà là người của Ma Đạo Lục Tông"}]},"nguon":["@c0629"]},{"id":"thien-sat-tong","name":"Thiên Sát Tông","cn":"天煞宗","type":"tong-mon","typeLabel":"Tông môn","diaBan":"","nhanVatChinh":["Đỗ Đông","Trung niên nho sinh","Vệ sư huynh"],"blurb":"Tông môn đã cài đệ tử lén đầu nhập ba đại môn phái nhiều năm, mưu đồ cướp thuần dịch Linh Nhãn Chi Thụ để cứu Huyền Thiên Tiên Đằng.","detail":"Thiên Sát Tông cho đệ tử lén đầu nhập ba đại môn phái đã nhiều năm. Đỗ Đông (thiếu chủ Thiên Huyễn Tông) và Trung niên nho sinh (Vệ huynh, giả làm đệ tử Lạc Vân Tông) đều là thành viên. Chánh tà hai phái phát hiện Huyền Thiên Tiên Đằng cổ thụ thượng cổ gần Mộ Lan thảo nguyên đã héo, cần thuần dịch Linh Nhãn Chi Thụ để cứu sống, đây là mục đích hợp tác.","nguonGoc":"","trangThai":"hoat-dong","thanhVien":[{"ten":"Đỗ Đông","chucVu":"Đệ tử","tuChuong":"@c0630","trangThai":"dang-hoat-dong"},{"ten":"Trung niên nho sinh","chucVu":"Đệ tử cài vào Lạc Vân Tông","tuChuong":"@c0630","trangThai":"dang-hoat-dong"},{"ten":"Vệ sư huynh","chucVu":"Tu sĩ Nguyên Anh Kỳ, chỉ huy nhóm ẩn nặc","tuChuong":"@c0630","trangThai":"dang-hoat-dong"}],"tabs":{"tienTrinh":[{"chuong":"@c0630","loai":"xuất hiện","importance":"major","giaiDoan":"Lộ âm mưu","text":"Đỗ Đông và Nho sinh lộ thân phận đệ tử Thiên Sát Tông. Lão giả tóc rối tiết lộ đã cài đệ tử vào ba đại môn phái nhiều năm, mưu đồ cướp thuần dịch Linh Nhãn Chi Thụ để cứu Huyền Thiên Tiên Đằng.","anchor":"cho nên ta đã cho vài tên đệ tử lén đầu nhập vào làm đệ tử của ba đại môn phái đã nhiều năm rồi"}]},"nguon":["@c0630"]},{"id":"chanh-dao-minh","name":"Chánh đạo minh","cn":"正道盟","type":"lien-minh","typeLabel":"Liên minh","diaBan":"Không rõ","nhanVatChinh":["Trung niên nho sinh"],"blurb":"Liên minh chánh đạo, đã cài gián điệp (nho sinh họ Bạch) trong phe ma đạo. Có mối liên hệ bí mật thân cận với Ma đạo lục tông.","detail":"Nho sinh họ Bạch là gián điệp Chánh đạo minh cài trong phe ma đạo, tuân lệnh Đỗ Đông (thiếu chủ Thiên Huyễn Tông). Nho sinh ngạc nhiên về việc Chánh đạo minh và Ma đạo lục tông thân cận. Gián điệp bại lộ trong bẫy phản gián của ba phái.","thanhVien":[{"ten":"Trung niên nho sinh","chucVu":"Gián điệp cài trong ma đạo","tuChuong":"@c0631","trangThai":"bại lộ"}],"tabs":{"tienTrinh":[{"chuong":"@c0631","loai":"nhắc tới","importance":"normal","giaiDoan":"Gián điệp bại lộ","text":"Nho sinh họ Bạch bại lộ thân phận gián điệp Chánh đạo minh trong bẫy phản gián của ba phái. Lộ mối liên hệ bí mật giữa Chánh đạo minh và Ma đạo lục tông.","anchor":"không biết từ lúc nào mà Chánh đạo minh cùng Ma đạo lục tông thân cận như thế"}]},"nguon":["@c0631"]},{"id":"thien-dao-tong","name":"Thiên Đạo Tông","type":"tong-mon","typeLabel":"Tông môn","diaBan":"Không rõ","nhanVatChinh":[],"blurb":"Tông phái chánh đạo được ba phái (Lạc Vân Tông, Cổ Kiếm Môn, Hạo Nhiên Các) nhờ làm trung gian gây áp lực lên chánh ma lưỡng đạo sau vụ mai phục, nhưng bất thành.","detail":"Ba phái thông qua Thiên Đạo Tông hướng chánh ma lưỡng đạo mạnh mẽ gây áp lực sau khi trưởng lão Nguyên Anh kỳ họ Trình bị trọng thương và tu sĩ Kết Đan tử vong trong trận mai phục, nhưng đối phương không thừa nhận, tranh cãi vô kết quả.","tabs":{"tienTrinh":[{"chuong":"@c0633","loai":"nhac-toi","importance":"normal","giaiDoan":"Trung gian gây áp lực thất bại","text":"Ba phái thông qua Thiên Đạo Tông gây áp lực lên chánh ma lưỡng đạo nhưng đối phương không thừa nhận, bất thành.","anchor":"thông qua Thiên Đạo Tông hướng chánh ma lưỡng đạo mạnh mẽ gây áp lực"}]},"nguon":["@c0633"]},{"id":"mo-gia","name":"Mộ gia","cn":"慕家","type":"gia-toc","typeLabel":"Gia tộc","diaBan":"","nhanVatChinh":["Mộ Phái Linh","Trưởng lão Mộ gia"],"blurb":"Gia tộc của Mộ Phái Linh. Trưởng lão/tộc trưởng cường hoành ép Mộ Phái Linh thành thân với nam tử họ Ngôn, dọa cắt linh thạch và liên lụy người thân.","detail":"Gia tộc tu tiên có quan hệ với Lạc Vân Tông. Tộc trưởng Mộ gia định ra hôn ước hoang đường cho cháu gái Mộ Phái Linh với nam tử họ Ngôn, bất chấp ý nguyện của nàng. Dùng quyền cắt linh thạch tu luyện và đe dọa liên lụy người thân để ép buộc.","lanhDaoHienThoi":"Trưởng lão Mộ gia","thanhVien":[{"ten":"Mộ Phái Linh","chucVu":"Thành viên","tuChuong":"@c0634","trangThai":"gan-bo"}],"tabs":{"tienTrinh":[{"chuong":"@c0634","loai":"nhắc tới","importance":"normal","giaiDoan":"Ép hôn ước","trangThaiMoc":"hoạt động","text":"Tộc trưởng Mộ gia cường hoành ép Mộ Phái Linh thành thân với nam tử họ Ngôn, dọa cắt linh thạch và liên lụy người thân.","anchor":"Tộc trưởng Mộ gia, bởi vì cháu mình mang tiếng là nữ tử điêu ngoa, dĩ nhiên cường hoành định ra một cái hôn ước hoang đường"}]},"nguon":["@c0634","@c0640"]},{"id":"ngon-gia","name":"Ngôn gia","cn":"言家","type":"gia-toc","typeLabel":"Gia tộc tu tiên","diaBan":"Khê Quốc","nhanVatChinh":["Ngôn sư huynh"],"blurb":"Tu tiên gia tộc không nhỏ ở Khê Quốc, định gả Mộ Phái Linh vào để song tu với Ngôn sư huynh. Hôn ước bị chủ động giải trừ sau khi Mộ Phái Linh tự xưng là thị thiếp Hàn Lập.","detail":"Gia tộc tu tiên có quy mô không nhỏ tại Khê Quốc. Tộc trưởng Ngôn gia chủ động giải trừ hôn ước với Mộ gia và truyền âm phù xin lỗi Hàn Lập, khẳng định không biết chuyện nữ tử đã thành thị thiếp.","nguon":["@c0640"]},{"id":"ma-diem-tong","name":"Ma Diễm Tông","cn":"魔焰宗","type":"tong-mon","typeLabel":"Tông môn (Ma đạo)","diaBan":"Nguyên Vũ quốc","nhanVatChinh":[],"blurb":"Một trong Ma đạo lục tông, thế lực đứng đầu Nguyên Vũ quốc. Phó gia Nguyên Vũ quốc quy phục Ma Diễm Tông, liên tục đưa đệ tử và mỹ nữ trong tộc vào tông để củng cố chỗ dựa.","detail":"Ma Diễm Tông thuộc ma đạo lục tông, là thế lực kiểm soát Nguyên Vũ quốc sau khi ma đạo xâm lấn. Phó gia Nguyên Vũ quốc nhanh chóng đầu nhập Ma Diễm Tông, được tông nâng đỡ trở thành đệ nhất gia tộc, đổi lại liên tục cống nạp đệ tử và mỹ nữ.","nguon":["@c0644"],"tabs":{"tienTrinh":[{"chuong":"@c0644","loai":"xuất hiện","importance":"normal","giaiDoan":"Giới thiệu thế lực","text":"Ma Diễm Tông được nhắc tới là tông môn trong ma đạo lục tông, kiểm soát Nguyên Vũ quốc và nhận Phó gia quy phục.","anchor":"ngay lập tức đầu nhập Ma Diễm tông trong ma đạo lục tông"}]},"nguonGoc":"Một trong sáu tông ma đạo Thiên Nam","trangThai":"đang hoạt động","capNhatToi":"@c0644"},{"id":"pho-gia-nguyen-vu","name":"Phó gia Nguyên Vũ quốc","cn":"付家","type":"gia-toc","typeLabel":"Gia tộc tu tiên","diaBan":"Nguyên Vũ quốc","nhanVatChinh":[],"blurb":"Đệ nhất gia tộc Nguyên Vũ quốc hiện tại, nhanh chóng đầu nhập Ma Diễm Tông khi ma đạo xâm lấn, nhờ đó thế lực tăng vọt, áp đảo hai đại gia tộc khác.","detail":"Hơn trăm năm trước khi ma đạo xâm lấn, Phó gia Nguyên Vũ quốc nhanh chóng đầu nhập Ma Diễm Tông, không những không tổn thất mà còn vươn lên thành đệ nhất gia tộc, đồng thời liên tục đưa đệ tử và mỹ nữ trong tộc vào Ma Diễm Tông để củng cố chỗ dựa. Có quan hệ huyết mạch với Phó gia thuộc Bách Xảo Viện nhưng đã đoạn tuyệt sau khi bên Nguyên Vũ quốc đầu nhập ma đạo.","nguon":["@c0644"],"tabs":{"tienTrinh":[{"chuong":"@c0644","loai":"xuất hiện","importance":"normal","giaiDoan":"Giới thiệu gia tộc","text":"Phó gia Nguyên Vũ quốc được giới thiệu là đệ nhất gia tộc, đã đầu nhập Ma Diễm Tông khi ma đạo xâm lấn, đoạn tuyệt quan hệ với Phó gia Bách Xảo Viện.","anchor":"Bởi vậy trong đại kiếp đó Phó gia cũng không hề bị tổn thất nào"}]},"nguonGoc":"Gia tộc tu tiên lâu đời tại Nguyên Vũ quốc, có quan hệ huyết mạch với Phó gia Bách Xảo Viện","quanHe":"Quy phục Ma Diễm Tông, đoạn tuyệt với Phó gia Bách Xảo Viện","trangThai":"hưng thịnh","capNhatToi":"@c0644"},{"id":"quy-linh-mon","name":"Quỷ Linh Môn","cn":"鬼灵门","type":"tong-mon","typeLabel":"Tông môn","diaBan":"Việt Quốc","nhanVatChinh":["Toái Hồn Chân Nhân"],"blurb":"Môn phái lớn ở Việt Quốc, không nhận tu sĩ đã thuộc tông môn khác. Được Hàn Lập nhắc tới khi khai lai lịch giả, viện cớ không vào được Quỷ Linh Môn nên sang Nguyên Vũ Quốc tìm cơ hội.","detail":"Quỷ Linh Môn được La huynh nhắc là môn phái to ở Việt Quốc. Hàn Lập dùng tên Quỷ Linh Môn làm cớ giả để giải thích vì sao rời Việt Quốc sang Nguyên Vũ Quốc.","nguon":["@c0645","@c0665"],"tabs":{"tienTrinh":[{"chuong":"@c0665","loai":"nhac-toi","importance":"normal","giaiDoan":"Tổn thất đệ tử, truy tra bất thành","text":"Toái Hồn Chân Nhân xuất quan phát phù truyền tin cho các phân đàn tại Việt Quốc ra lệnh truy tra vụ đệ tử Kết Đan bị giết, nhưng đối phương đã rời xa.","anchor":"lập tức tra rõ chuyện mấy tên đệ tử bị ngộ hại"}]},"trangThai":"hưng, tổn thất đệ tử Kết Đan"},{"id":"banh-dich-song-hung","name":"Bành Dịch Song Hung","type":"bang-hoi","typeLabel":"Nhóm hung tu","diaBan":"Nguyên Vũ Quốc","nhanVatChinh":["Tu sĩ ục ịch họ La","Đại hán đầu hói"],"blurb":"Cặp hung tu tán tu gồm tu sĩ ục ịch họ La và đại hán đầu hói, có xú danh lan rộng trong giới tán tu Nguyên Vũ Quốc, chuyên nhắm người đoạt bảo.","detail":"Bành Dịch Song Hung là danh xưng chung của hai tu sĩ giấu tu vi Trúc Cơ Trung Kỳ, chuyên đóng vai yếu hơn để dụ mục tiêu rồi đánh lén đoạt tài vật. Xú danh của chúng khiến tán tu khác vừa thấy đã vội vàng tránh xa. Chúng nhắm tới Hàn Lập vì thấy hắn có phi kiếm ngự khí đỉnh cấp và túi trữ vật căng phồng, nhưng không biết hắn thực chất là tu sĩ Nguyên Anh Kỳ cải dung.","nguon":["@c0646"],"tabs":{"tienTrinh":[{"chuong":"@c0646","loai":"xuat-hien","importance":"normal","trangThaiMoc":"Đang phục kích Hàn Lập","giaiDoan":"Bàn mưu đoạt bảo","text":"Lập kế giết Hàn Lập đoạt bảo, bố trí trận pháp vây địch trong tiểu cốc, dẫn hắn tới tiểu sơn phục kích nhưng bị vạch mặt.","anchor":"dĩ nhiên gặp phải Bành Dịch Song Hung chúng ta, hiển nhiên không thể bỏ qua"}]}},{"id":"dam-gia","name":"Đàm Gia","cn":"","type":"gia-toc","typeLabel":"Gia tộc tu tiên","diaBan":"Nguyên Vũ Quốc","nhanVatChinh":[],"blurb":"Gia tộc tu tiên tại Nguyên Vũ Quốc, kẻ thù tối thù địch của Phó Gia. Từng bị Phó Gia giết tu sĩ chủ lực chống ma đạo, nay tu sĩ cao cấp suy giảm, ẩn nấp hận thấu xương, có khả năng liên thủ với Hỗ Gia báo thù.","detail":"Từng tranh hơn thua với Phó Gia, bị Phó Gia ra tay giết tu sĩ chủ lực để lấy lòng Ma Diễm Môn. Hiện tu sĩ cao cấp không còn bao nhiêu, bị chèn ép phải ẩn nấp. Phó Gia nghi ngờ Đàm Gia có thể liên thủ với Hỗ Gia hoặc liên hợp tiểu phái đánh bất ngờ nhân dịp lễ mừng thọ.","nguon":["@c0649"]},{"id":"ho-gia","name":"Hỗ Gia","cn":"","type":"gia-toc","typeLabel":"Gia tộc tu tiên","diaBan":"Nguyên Vũ Quốc","nhanVatChinh":[],"blurb":"Gia tộc tu tiên tại Nguyên Vũ Quốc, cùng Đàm Gia là kẻ thù nhất của Phó Gia. Cùng cảnh ngộ suy tàn sau khi bị Phó Gia chèn ép, có khả năng liên thủ báo thù.","detail":"Cùng Đàm Gia bị Phó Gia ra tay giết tu sĩ chủ lực chống ma đạo để lấy lòng Ma Diễm Môn, nay hận thấu xương, tu sĩ cao cấp suy giảm, có thể liên thủ đánh bất ngờ nhân dịp thọ.","nguon":["@c0649"]},{"id":"ma-diem-mon","name":"Ma Diễm Môn","cn":"","type":"tong-phai","typeLabel":"Tông phái","diaBan":"","nhanVatChinh":[],"blurb":"Tông phái có tu sĩ hoạt động tại Nguyên Vũ Quốc. Hai tu sĩ bị Hàn Lập thuận tay giết khi diệt Phó Gia.","detail":"Hàn Lập nhắc khi diệt Phó Gia cũng thuận tay giết hai tu sĩ Ma Diễm Môn, không muốn rước phiền toái từ tông phái này.","nguon":["@c0653"]},{"id":"toai-hon-mon","name":"Toái Hồn Môn","cn":"","type":"phan-he","typeLabel":"Phân hệ","diaBan":"Yểm Nguyệt Tông, có phân đàn tại Việt Quốc","nhanVatChinh":["Toái Hồn Chân Nhân","Tam sư huynh Toái Hồn Môn","Ngũ sư muội Toái Hồn Môn","Khuyết sư đệ","Vu Hồng"],"blurb":"Phân hệ trong Quỷ Linh Môn, do Toái Hồn Chân Nhân đứng đầu. Có ít nhất 7 đệ tử và hệ thống phân đàn (Nhạc phân đàn và các phân đàn khác).","detail":"Toái Hồn Môn trú tại phòng bí mật trong Yểm Nguyệt Tông, hoạt động dưới danh nghĩa Quỷ Linh Môn. Có hệ thống phân đàn với các Đàn chủ riêng. Kỷ luật khắc nghiệt, Nhị sư huynh và Thất sư đệ từng bị xử phạt vì làm không xong việc. Lục sư đệ Vu Hồng bị Hàn Lập giết, ba đệ tử Kết Đan Kỳ còn lại được lệnh truy tìm hung thủ.","nguonGoc":"Phân hệ của Quỷ Linh Môn","lanhDaoHienThoi":"Toái Hồn Chân Nhân","thanhVien":[{"ten":"Toái Hồn Chân Nhân","chucVu":"Chưởng môn","tuChuong":"@c0656","trangThai":"song"},{"ten":"Tam sư huynh Toái Hồn Môn","chucVu":"Tam đệ tử","tuChuong":"@c0656","trangThai":"song"},{"ten":"Ngũ sư muội Toái Hồn Môn","chucVu":"Ngũ đệ tử","tuChuong":"@c0656","trangThai":"song"},{"ten":"Khuyết sư đệ","chucVu":"Đệ tử","tuChuong":"@c0656","trangThai":"song"},{"ten":"Vu Hồng","chucVu":"Lục đệ tử","tuChuong":"@c0656","trangThai":"tu-vong"}],"tabs":{"tienTrinh":[{"chuong":"@c0656","loai":"xuất hiện","importance":"major","giaiDoan":"Ra mắt sau khi Lục sư đệ bị giết","trangThaiMoc":"Hoạt động","text":"Toái Hồn Chân Nhân cảm ứng bổn mạng lệnh bài của Lục sư đệ Vu Hồng tắt linh quang, triệu tập ba đệ tử Kết Đan Kỳ ra lệnh truy tìm hung thủ. Ba người phát hiện động phủ cũ của Hàn Lập tại Thái Nhạc Sơn chỉ còn hố to.","anchor":"đã là đệ tử của Toái Hồn Môn thì không thể nào chết không minh bạch được"}]},"capNhatToi":"@c0656","nguon":["@c0656"]},{"id":"that-huyen-mon","name":"Thất Huyền Môn","cn":"七玄门","type":"tong-mon","typeLabel":"Tông môn","diaBan":"Thành Kinh Châu","nhanVatChinh":["Hàn Lập"],"blurb":"Tông môn từng một thời hùng bá ở thành Kinh Châu. Tiên tổ nhà Hàn và nhà Lệ đều là nội môn đệ tử nơi đây.","detail":"Được hậu duệ phàm nhân nhà Hàn nhắc lại khi kể nguồn gốc mối giao tình Hàn-Lệ. Từng hùng bá thành Kinh Châu hơn trăm năm trước thời hiện tại của Hàn Lập. Hàn Lập cũng nhớ tới cây cờ nhỏ màu đen Thất Huyền Môn trên xe ngựa ngày xưa.","tabs":{"tienTrinh":[{"chuong":"@c0657","loai":"nhắc tới","importance":"normal","giaiDoan":"Được hậu nhân phàm nhắc tới như quá khứ đã qua","text":"Nho sinh họ Hàn kể Thất Huyền Môn từng một thời hùng bá ở thành Kinh Châu hơn mười năm trước (lịch phàm). Tiên tổ hai nhà Hàn-Lệ đều là nội môn đệ tử nơi đây.","anchor":"Người còn nhớ rõ hơn mười năm trước một thời hùng bá ở thành Kinh Châu, Thất Huyền Môn hay không"}]},"nguon":["@c0657"]},{"id":"han-gia-kinh-chau","name":"Hàn gia Kính Châu","cn":"韩家","type":"gia-toc","typeLabel":"Gia tộc phàm nhân","diaBan":"Kính Châu, Ngũ Lý Câu (cũ)","nhanVatChinh":["Hàn Lập","Hàn thị lang"],"blurb":"Gia tộc gốc ở Ngũ Lý Câu — quê cũ của Hàn Lập, quật khởi chưa đầy trăm năm nhờ con cháu bên ngoại thi đậu làm quan lớn, nay có thanh thế ngang hai nhà Phạm, Lý, trở thành tam đại thế gia Kính Châu.","detail":"Hàn gia đã dời khỏi Ngũ Lý Câu hơn mười dặm từ hơn mười năm trước. Đang tổ chức tế tổ long trọng, Châu lệnh đại nhân tự mình tới bái hội, phát tín hàm triệu tộc nhân quay về. Tại Hàn Gia Từ có thờ phụng mấy trăm linh vị và bản chép tay gia tổ.","nguonGoc":"Gia tộc phàm nhân tại Ngũ Lý Câu, quật khởi nhờ một thế hệ con cháu bên ngoại làm quan lớn, tích lũy dần trong chưa đầy trăm năm.","quyMo":"Tam đại thế gia Kính Châu, ngang nhà Phạm và nhà Lý","trangThai":"hưng thịnh","capNhatToi":"@c0658","tabs":{"tienTrinh":[{"chuong":"@c0658","loai":"nhắc tới","importance":"major","giaiDoan":"Quật khởi thành tam đại thế gia Kính Châu","text":"Hai nho sinh tửu lâu bàn luận Hàn gia đã phát triển nhanh chưa đầy trăm năm, thanh thế ngang hai nhà Phạm, Lý, tổ chức tế tổ long trọng được Châu lệnh bái hội.","anchor":"Hàn gia phát triển rất nhanh sau này cũng như hai nhà Phạm, Lý trở thành tam đại thế gia ở Kính Châu này đây"}]},"nguon":["@c0658"]},{"id":"le-gia","name":"Lệ gia","cn":"","type":"gia-toc","typeLabel":"Gia tộc","diaBan":"Không rõ","nhanVatChinh":["Lệ Phi Vũ","Lệ Phong"],"blurb":"Gia tộc phàm nhân, hậu duệ Lệ Phi Vũ. Đã thông gia với Hàn gia qua con gái Lệ Phi Vũ. Có cơ nghiệp đồ sộ truyền đời.","detail":"Gia tộc phàm nhân do Lệ Phi Vũ gây dựng. Con gái Lệ Phi Vũ kết thông gia với Hàn gia, từ đó hai nhà gắn bó. Đại hán râu quai nón (Lệ Phong) là hậu nhân hiện tại, có sức mạnh thể chất đáng kể nhưng vẫn là phàm nhân.","nguon":["@c0659"]},{"id":"ngu-sac-mon","name":"Ngũ Sắc Môn","cn":"五色门","type":"tong-mon","typeLabel":"Tông môn","diaBan":"Lam Châu (đã mất)","nhanVatChinh":[],"blurb":"Tông môn từng uy chấn Lam Châu hơn trăm năm, có bóng dáng Linh Thú Sơn đứng sau. Đã sụp đổ hoàn toàn, bị Thiên Nhất Hội thay thế.","detail":"Ngũ Sắc Môn từng uy chấn Lam Châu hơn trăm năm nhưng đã không còn tồn tại. Hàn Lập suy luận nguyên nhân: Ngũ Sắc Môn có bóng dáng Linh Thú Sơn đứng sau, Linh Thú Sơn khi quyết chiến ma đạo đã phản thủ ngả về Ngự Linh Tông, Việt Quốc bị Quỷ Linh Môn khống chế nên Ngũ Sắc Môn suy tàn.","trangThai":"diệt","tabs":{"tienTrinh":[{"chuong":"@c0661","loai":"diệt/sáp nhập","importance":"major","giaiDoan":"Sụp đổ hoàn toàn","trangThaiMoc":"diệt","text":"Ngũ Sắc Môn từng uy chấn Lam Châu hơn trăm năm đã không còn tồn tại, bị Thiên Nhất Hội thay thế. Nguyên nhân: Linh Thú Sơn phản thủ ngả Ngự Linh Tông, Việt Quốc bị Quỷ Linh Môn khống chế.","anchor":"ngay cả Lam Châu Ngũ Sắc Môn từng uy chấn một thời hơn trăm năm đã không còn tồn tại"}]},"nguon":["@c0661"]},{"id":"thien-nhat-hoi","name":"Thiên Nhất Hội","cn":"","type":"the-luc","typeLabel":"Thế lực","diaBan":"Lam Châu","nhanVatChinh":[],"blurb":"Thế lực tân quật khởi thay thế Ngũ Sắc Môn ở Lam Châu.","detail":"Thế lực mới nổi ở Lam Châu, thay thế vị trí của Ngũ Sắc Môn sau khi tông môn này sụp đổ.","nguon":["@c0661"]},{"id":"tu-binh-bang","name":"Tứ Bình Bang","cn":"","type":"the-luc","typeLabel":"Thế lực","diaBan":"Gia Nguyên Thành (đã mất)","nhanVatChinh":["Tôn Nhị Cẩu"],"blurb":"Tổ chức phàm nhân của Tôn Nhị Cẩu, đã tan thành mây khói.","detail":"Tổ chức phàm nhân do Tôn Nhị Cẩu gây dựng, đến thời điểm Hàn Lập ghé Gia Nguyên Thành đã tan thành mây khói.","trangThai":"diệt","nguon":["@c0661"]},{"id":"lien-minh-chin-nuoc","name":"Liên minh chín nước","cn":"九国联盟","type":"lien-minh","typeLabel":"Liên minh","diaBan":"Phía bắc Thiên Nam đế quốc","nhanVatChinh":["Cửu Quốc Minh"],"blurb":"Liên minh của chín nước tu tiên tại Thiên Nam, tổng đàn là tòa thành tu sĩ duy nhất Thiên Nam, nơi tổ chức Giao dịch hội. Ngoài Cửu Quốc Minh lão quái còn có sáu bảy tu sĩ Nguyên Anh Trung Kỳ trấn giữ.","detail":"Tổng đàn liên minh chín nước tọa lạc phía bắc Thiên Nam đế quốc, là tòa thâm sơn do thiên nhiên tạo thành, đồng thời là tòa thành tu sĩ duy nhất tại Thiên Nam. Ngoài Cửu Quốc Minh lão quái, còn có thêm sáu bảy tu sĩ Nguyên Anh Trung Kỳ khác trấn giữ. Liên minh tổ chức Giao dịch hội định kỳ, mở địa trận Thượng Nguyên Diệt Quang trận bảo vệ khu vực, phòng đấu giá do Cửu Quốc Minh làm nhà cái tiếp nhận tài liệu trân quý.","nguonGoc":"Liên minh của chín nước tu tiên Thiên Nam","lanhDaoHienThoi":"Cửu Quốc Minh","quyMo":"Nhiều Nguyên Anh Trung Kỳ trấn giữ","tabs":{"tienTrinh":[{"chuong":"@c0670","loai":"nhắc tới","importance":"normal","giaiDoan":"Tổ chức Giao dịch hội","text":"Tổng đàn liên minh chín nước mở Giao dịch hội, kích hoạt Thượng Nguyên Diệt Quang trận, phòng đấu giá do Cửu Quốc Minh làm nhà cái bắt đầu tiếp nhận tài liệu.","anchor":"Nguyên Anh Trung Kỳ ngoài Cửu Quốc Minh lão quái còn có thêm sáu bảy người khác"}]},"nguon":["@c0670"]},{"id":"thien-truc-giao","name":"Thiên Trúc Giáo","cn":"天竺教","type":"tong-mon","typeLabel":"Tông môn","blurb":"Giáo phái nắm giữ chân kinh Khôi Lỗi Thuật nhưng không có tu sĩ Nguyên Anh. Hàn Lập nhớ về Thiên Trúc Giáo khi thấy khôi lỗi thú của Thiên Tinh Chân Nhân không giống loại trong chân kinh.","detail":"Thiên Trúc Giáo sở hữu chân kinh ghi lại Khôi Lỗi Thuật. Hàn Lập biết giáo phái này không có tu sĩ Nguyên Anh. Khi thấy khôi lỗi thú của Thiên Tinh Chân Nhân không phải loại trong chân kinh Thiên Trúc Giáo, Hàn Lập tự hỏi liệu Thiên Tinh Chân Nhân có liên quan tới giáo phái này hay tu luyện một loại Khôi Lỗi Thuật khác.","nguon":["@c0677"]},{"id":"ton-gia","name":"Tôn gia","cn":"","type":"gia-toc","typeLabel":"Gia tộc","diaBan":"Thiên Nam","nhanVatChinh":["Tôn Nhị Cẩu","Tôn Hỏa"],"blurb":"Gia tộc hậu nhân của Tôn Nhị Cẩu, năm xưa Tôn Nhị Cẩu thề dòng tộc sẽ nhận Hàn Lập làm chủ nhưng chưa từng chính thức thực hiện vì Hàn Lập vắng mặt ở Thiên Nam.","detail":"Tôn Hỏa là huyền tôn đời thứ bảy của Tôn Nhị Cẩu. Dòng tộc mang lời thề nhận Hàn Lập làm chủ nhân nhưng chưa bao giờ chính thức thực hiện do Hàn Lập không ở Thiên Nam. Hàn Lập đưa ra hai lựa chọn cho Tôn Hỏa: cắt đứt quan hệ hoặc kế thừa lời thề.","nguon":["@c0680"]},{"id":"nguoi-mo-lan","name":"Người Mộ Lan","cn":"慕蘭人","type":"chung-toc","typeLabel":"Chủng tộc","diaBan":"Mộ Lan hư không thảo nguyên và khu vực biên giới Thiên Nam","nhanVatChinh":[],"blurb":"Chủng tộc sử dụng pháp sĩ (khác tu sĩ), từng đình chiến với tu sĩ Thiên Nam hơn trăm năm trước, nay xuất động đội tiên phong mở màn chiến tranh mới.","detail":"Người Mộ Lan là chủng tộc có hệ thống tu luyện riêng biệt, sử dụng pháp sĩ thay vì tu sĩ. Linh thuật đặc trưng là Phong Linh Thuật, có thể tạo bão cát ngăn thần thức dò xét. Đã đình chiến với tu sĩ Thiên Nam hơn trăm năm, nay đội tiên phong xuất hiện với bão cát quy mô gấp trăm ngàn lần bình thường, bên trong ẩn tàng nhiều pháp sĩ, có thể có người ngang tu vi Nguyên Anh Kỳ. Pháp sĩ ẩn nặc trong các phong trụ di chuyển, đồng thời có khả năng thi triển cấm chế ám toán nhóm tu sĩ Nguyên Anh Kỳ.","nguonGoc":"Chủng tộc bản địa Mộ Lan thảo nguyên","trangThai":"Khai chiến","tabs":{"tienTrinh":[{"chuong":"@c0686","loai":"khai chiến","importance":"major","giaiDoan":"Đội tiên phong xuất hiện, mở màn chiến tranh mới","trangThaiMoc":"Khai chiến","text":"Đội tiên phong Người Mộ Lan xuất hiện với bão cát Phong Linh Thuật quy mô gấp trăm ngàn lần bình thường, bên trong ẩn tàng nhiều pháp sĩ. Chiến tranh mới sắp bắt đầu sau hơn trăm năm đình chiến.","anchor":"Trăm năm hơn thời gian cũng không sai biệt lắm. Đủ có thể làm cho Người Mộ Lan nghỉ ngơi dưỡng sức xong"}]},"capNhatToi":"@c0686","nguon":["@c0686"]},{"id":"hoang-sa-bo","name":"Hoàng Sa Bộ","cn":"黃沙部","type":"bo-toc","typeLabel":"Bộ tộc Mộ Lan","diaBan":"Mộ Lan thảo nguyên","nhanVatChinh":["Đại Thượng Sư (Hoàng Sa Bộ)","Pháp sĩ bạch quang (Hoàng Sa Bộ)","Pháp sĩ điện hồ (Hoàng Sa Bộ)"],"blurb":"Bộ tộc Mộ Lan đang dẫn đầu liên quân mười đại bộ tộc nhờ sở hữu trấn tộc thánh khí Ma Trần Phiên (36 can). Có Đại Thượng Sư đồng cấp Nguyên Anh chỉ huy, sở hữu Tu Di Trùng thượng cổ kỳ trùng.","detail":"Bộ tộc lớn trong liên quân mười đại bộ tộc Mộ Lan, hiện giữ vị trí dẫn đầu liên quân nhờ trấn tộc thánh khí Ma Trần Phiên. Quan hệ với Thiên Phong Bộ không hòa thuận. Cố vây nhóm tu sĩ Hàn Lập bằng ảo trận cát vàng nhưng thất bại do uy lực quá yếu so với đám Nguyên Anh.","lanhDaoHienThoi":"Đại Thượng Sư (Hoàng Sa Bộ)","quyMo":"Đại bộ tộc trong liên quân mười đại bộ tộc","trangThai":"Hưng thịnh, dẫn đầu liên quân","quanHe":"Không hòa thuận với Thiên Phong Bộ; liên minh với chín bộ tộc khác","tranPhai":"Ma Trần Phiên (trấn tộc thánh khí, 36 can)","thanhVien":[{"ten":"Đại Thượng Sư (Hoàng Sa Bộ)","chucVu":"Đại Thượng Sư (thủ lĩnh)","tuChuong":"@c0687","trangThai":"hoat-dong"},{"ten":"Pháp sĩ bạch quang (Hoàng Sa Bộ)","chucVu":"Thượng Sư","tuChuong":"@c0687","trangThai":"hoat-dong"},{"ten":"Pháp sĩ điện hồ (Hoàng Sa Bộ)","chucVu":"Pháp sĩ","tuChuong":"@c0687","trangThai":"hoat-dong"}],"tabs":{"tienTrinh":[{"chuong":"@c0687","loai":"khai chiến","importance":"major","trangThaiMoc":"Vây đám tu sĩ thất bại","text":"Bố trí ảo trận cát vàng vây nhóm tu sĩ Hàn Lập nhưng cấm chế bị phá dễ dàng. Đại Thượng Sư từ chối dùng trấn tộc thánh khí Ma Trần Phiên, quyết định chờ quân chủ lực đến. Hé lộ vị trí dẫn đầu liên quân mười đại bộ tộc nhờ Ma Trần Phiên và mâu thuẫn nội bộ với Thiên Phong Bộ.","anchor":"chúng ta dựa vào cái gì yên ổn ngồi ở vị trí dẫn đầu liên quân mười đại bộ tộc"}]},"nguon":["@c0687"]},{"id":"thien-phong-bo","name":"Thiên Phong Bộ","cn":"天風部","type":"bo-toc","typeLabel":"Bộ tộc Mộ Lan","diaBan":"Mộ Lan thảo nguyên","nhanVatChinh":["Mục Thượng Sư (Thiên Phong Bộ)"],"blurb":"Bộ tộc Mộ Lan sở hữu trấn tộc bảo vật Ngự Phong Xa có tốc độ kinh khủng. Mục Thượng Sư tạm chỉ huy tiên phong liên quân, vốn không hòa thuận với Hoàng Sa Bộ.","detail":"Bộ tộc Mộ Lan khác trong liên quân mười đại bộ tộc, do Mục Thượng Sư lãnh đạo. Sở hữu trấn tộc bảo vật Ngự Phong Xa có tốc độ cực cao. Vốn không hòa thuận với Hoàng Sa Bộ. Mục Thượng Sư đưa tin khiến Hoàng Sa Bộ vây nhóm tu sĩ rồi đi liên lạc bộ lạc khác, bị nghi mượn cơ trả thù.","lanhDaoHienThoi":"Mục Thượng Sư (Thiên Phong Bộ)","trangThai":"Hoạt động trong liên quân","quanHe":"Không hòa thuận với Hoàng Sa Bộ","tranPhai":"Ngự Phong Xa (trấn tộc bảo vật)","thanhVien":[{"ten":"Mục Thượng Sư (Thiên Phong Bộ)","chucVu":"Thượng Sư (thủ lĩnh)","tuChuong":"@c0687","trangThai":"hoat-dong"}],"tabs":{"tienTrinh":[{"chuong":"@c0687","loai":"nhắc tới","importance":"normal","trangThaiMoc":"Bị nghi ngờ ý đồ","text":"Mục Thượng Sư đưa tin khiến Hoàng Sa Bộ vây nhóm tu sĩ rồi đi liên lạc bộ lạc khác, bị Đại Thượng Sư nghi có tâm bất lương mượn cơ trả thù.","anchor":"hai bộ lạc chúng ta nguyên bản vốn không thế nào thực sự hòa thuận"}]},"nguon":["@c0687"]},{"id":"lien-quan-muoi-dai-bo-toc-mo-lan","name":"Liên quân mười đại bộ tộc (Mộ Lan)","cn":"","type":"lien-minh","typeLabel":"Liên minh bộ tộc","diaBan":"Mộ Lan thảo nguyên","nhanVatChinh":[],"blurb":"Liên minh mười đại bộ tộc Mộ Lan, hiện do Hoàng Sa Bộ dẫn đầu. Quân chủ lực đang tập hợp, chưa tới chiến trường.","detail":"Liên quân gồm mười đại bộ tộc Mộ Lan cùng nhiều tiểu bộ tộc, hiện do Hoàng Sa Bộ dẫn đầu nhờ trấn tộc thánh khí Ma Trần Phiên. Quân chủ lực đang trên đường tới.","quyMo":"Mười đại bộ tộc và nhiều tiểu bộ tộc","trangThai":"Đang tập hợp lực lượng","tabs":{"tienTrinh":[{"chuong":"@c0687","loai":"nhắc tới","importance":"normal","trangThaiMoc":"Được nhắc tới, quân chủ lực chưa đến","text":"Đại Thượng Sư nhắc tới liên quân mười đại bộ tộc, Hoàng Sa Bộ đang dẫn đầu, chờ quân chủ lực đến thì đại thắng.","anchor":"chúng ta dựa vào cái gì yên ổn ngồi ở vị trí dẫn đầu liên quân mười đại bộ tộc"}]},"nguon":["@c0687"]},{"id":"ma-mon","name":"Ma Môn","type":"the-luc","typeLabel":"Thế lực","diaBan":"Không rõ","nhanVatChinh":["Vương Thiên Cổ","Yến Như Yên","Vương Thiền"],"blurb":"Thế lực đối lập với Thiên Đạo Minh. Hàn Lập khẳng định quan hệ hai bên là thù địch, không thể hóa giải.","detail":"Thế lực mà Vương Thiên Cổ, Yến Như Yên và Vương Thiền thuộc về. Hàn Lập tự xưng thuộc Thiên Đạo Minh, khẳng định Ma Môn và Thiên Đạo Minh vốn là quan hệ thù địch, cự tuyệt đề nghị hóa giải cừu oán từ Yến Như Yên.","nguon":["@c0697"]},{"id":"thien-cuc-mon","name":"Thiên Cực Môn","cn":"天极门","type":"tong-mon","typeLabel":"Tông môn","diaBan":"","nhanVatChinh":[],"blurb":"Thế lực chính đạo, có mấy vị trưởng lão đã lén kết giao với Nam Lũng Hầu, Nam Lũng Hầu có ý gia nhập và trợ giúp Thiên Cực Môn vào Trụy Ma Cốc lấy bảo.","detail":"Thế lực chính đạo được lão giả họ Vân nhắc tới. Nam Lũng Hầu lén kết giao với mấy vị trưởng lão Thiên Cực Môn, có ý gia nhập tông môn này và trợ giúp chính đạo vào Trụy Ma Cốc lấy bảo. Đây là lý do lão giả họ Vân (Trưởng lão Quỷ Linh Môn) quyết hạ độc thủ đối với Nam Lũng Hầu, nhằm ngăn thế lực chính đạo bành trướng.","nguon":["@c0701"],"tabs":{"tienTrinh":[{"chuong":"@c0701","loai":"nhắc tới","importance":"normal","giaiDoan":"Bị tiết lộ đang lôi kéo Nam Lũng Hầu","text":"Lão giả họ Vân tiết lộ Nam Lũng Hầu lén kết giao trưởng lão Thiên Cực Môn, có ý gia nhập và trợ giúp chính đạo vào Trụy Ma Cốc lấy bảo.","anchor":"hắn lại len lén kết giao với mấy vị trưởng lão Thiên Cực Môn, cũng có ý gia nhập tông môn này"}]}},{"id":"hoa-y-mon","name":"Hóa Ý Môn","cn":"化意门","type":"tong-mon","typeLabel":"Tông môn","diaBan":"Thiên Nam","nhanVatChinh":["Ngụy Ly Thần"],"blurb":"Tông môn tu tiên ở Thiên Nam, có trưởng lão Ngụy Ly Thần là tu sĩ Nguyên Anh kỳ, kỳ tài trong ba trăm năm kết thành Nguyên Anh.","detail":"Trưởng lão Ngụy Ly Thần trong ba trăm năm đã kết thành Nguyên Anh, thần thông thâm sâu khó lường, được xem là kỳ tài tu tiên Thiên Nam. Sắp tổ chức song tu đại điển liên tông giữa Ngụy Ly Thần và Nam Cung Uyển (trưởng lão Yểm Nguyệt Tông).","tabs":{"tienTrinh":[{"chuong":"@c0707","loai":"nhắc tới","importance":"normal","giaiDoan":"Được nhắc đến lần đầu","text":"Trưởng lão Ngụy Ly Thần là tu sĩ Nguyên Anh kỳ, kỳ tài Thiên Nam, sắp cùng Nam Cung Uyển cử hành song tu đại điển.","anchor":"vị trưởng lão Ngụy Ly Thần của Hóa Ý môn trong ba trăm năm đã kết thành Nguyên Anh"},{"chuong":"@c0708","loai":"nhac-toi","importance":"normal","giaiDoan":"Được nhắc đến như thế lực cản đường Hàn Lập","text":"Được nhắc là một trong hai đại tông phái lớn nhất Cửu Quốc Minh, có bốn năm trưởng lão Nguyên Anh kỳ. Hàn Lập cân nhắc ám sát Ngụy Ly Thần nhưng đánh giá Hóa Ý Môn quá mạnh.","anchor":"Hóa Ý Môn chẳng phải là loại tiểu tông tiểu phái gì mà chính là một trong hai đại tông phái lớn nhất của Cửu Quốc Minh"},{"chuong":"@c0712","loai":"nhắc tới","importance":"normal","giaiDoan":"Lần đầu lộ diện","text":"Được nhắc đến: Ngụy Ly Thần là trưởng lão Hóa Ý Môn, nếu cưới Nam Cung Uyển sẽ thoát ly tông môn.","anchor":"Ngụy Ly Thần sau khi lấy thiếp sẽ nguyện ý thoát ly Hóa Ý Môn, gia nhập Yểm Nguyệt Tông"}]},"thanhVien":[{"ten":"Ngụy Ly Thần","chucVu":"Trưởng lão","tuChuong":"@c0707","trangThai":"dang-o"}],"nguon":["@c0707","@c0708","@c0712"],"trangThai":"hien-dien"},{"id":"vien-gia","name":"Viên gia","cn":"","type":"gia-toc","typeLabel":"Gia tộc tu tiên","diaBan":"Phía Bắc Bắc Lương Quốc","nhanVatChinh":["Viên Khôn"],"blurb":"Gia tộc tu tiên trung đẳng kỳ cựu ở phía Bắc Bắc Lương Quốc, từng trợ giúp lục phái và Yểm Nguyệt Tông đặt chân tại đây.","detail":"Viên gia là gia tộc tu tiên trung đẳng kỳ cựu ở phía Bắc Bắc Lương Quốc. Từng trợ giúp lục phái và Yểm Nguyệt Tông khi họ mới tới Bắc Lương Quốc, nhờ đó Yểm Nguyệt Tông hứa hẹn tưởng thưởng bồi thường. Viên Khôn là cháu ruột gia chủ, được giao làm quản sự trong Yểm Nguyệt Tông.","quyMo":"Gia tộc tu tiên trung đẳng","trangThai":"hien-dien","tabs":{"tienTrinh":[{"chuong":"@c0708","loai":"nhac-toi","importance":"bridge","giaiDoan":"Được giới thiệu lai lịch","text":"Được giới thiệu là gia tộc tu tiên trung đẳng kỳ cựu từng trợ giúp lục phái đặt chân Bắc Lương Quốc.","anchor":"phía Bắc của Bắc Lương Quốc có một gia tộc tu tiên trung đẳng kỳ cựu"}]},"capNhatToi":"@c0708","nguon":["@c0708"]},{"id":"cu-kiem-mon","name":"Cự Kiếm Môn","cn":"","type":"tong-mon","typeLabel":"Tông môn","blurb":"Một trong lục phái Việt Quốc.","detail":"Cự Kiếm Môn là một trong lục phái Việt Quốc, hiện trú chân tại Bắc Lương Quốc cùng các phái khác.","nguon":["@c0708"]},{"id":"mo-lan-phap-si","name":"Mộ Lan pháp sĩ","cn":"穆兰法士","type":"the-luc","typeLabel":"Thế lực","diaBan":"Phong Nguyên Quốc","nhanVatChinh":[],"blurb":"Thế lực pháp sĩ từ Phong Nguyên Quốc, kiếm được man hoang cự thú từ nguồn bí ẩn, dùng chúng đại thắng quân Cửu Quốc Minh liên tiếp ba trận.","detail":"Đại quân Mộ Lan pháp sĩ thuộc Phong Nguyên Quốc đang đại chiến tại biên giới Ngu Quốc. Không rõ từ đâu kiếm được một số man hoang cự thú, tu sĩ Cửu Quốc Minh không ứng phó được nên liên tục thảm bại. Thế tiến công cực hung hãn.","nguon":["@c0718"],"tabs":{"tienTrinh":[{"chuong":"@c0718","loai":"khai chiến","importance":"major","trangThaiMoc":"thắng thế","giaiDoan":"Đại thắng Cửu Quốc Minh","text":"Dùng man hoang cự thú từ nguồn bí ẩn đánh bại quân chủ lực Cửu Quốc Minh liên tiếp ba trận, buộc đối phương phải phát hội minh cầu viện.","anchor":"Mộ Lan pháp sĩ không biết kiếm được một số man hoang cự thú từ đâu, tu sĩ Cửu Quốc Minh ứng phó không được nên mới liên tục thảm bại"}]}},{"id":"boi-diep-tong","name":"Bối Diệp Tông","cn":"","type":"tong-mon","typeLabel":"Tông môn","diaBan":"Cửu Quốc Minh, Thiên Nam","nhanVatChinh":["Ngô Bằng"],"blurb":"Một trong hai đại phái hàng đầu Cửu Quốc Minh, tông chủ là Ngô Bằng (Nguyên Anh trung kỳ), đang chủ sự liên minh chống Mộ Lan.","detail":"Bối Diệp Tông cùng Hóa Ý Môn là hai đại phái hàng đầu của Cửu Quốc Minh. Tông chủ Ngô Bằng đang dẫn đầu liên minh tu sĩ Thiên Nam chống lại cuộc xâm lấn của pháp sĩ Mộ Lan.","lanhDaoHienThoi":"Ngô Bằng","thanhVien":[{"ten":"Ngô Bằng","chucVu":"Tông chủ","tuChuong":"@c0720","trangThai":"dang-co"}],"tabs":{"tienTrinh":[{"chuong":"@c0720","loai":"xuat-hien","importance":"normal","giaiDoan":"Lộ diện tại hội nghị điện nghị","text":"Được giới thiệu là một trong hai đại phái hàng đầu Cửu Quốc Minh, tông chủ Ngô Bằng chủ trì hội nghị chống Mộ Lan.","anchor":"Bối Diệp Tông cùng Hóa Ý Môn là hai đại phái hàng đầu của Cửu Quốc Minh"}]},"nguon":["@c0720"]},{"id":"am-anh-tong","name":"Ám Ảnh Tông","cn":"","type":"tong-mon","typeLabel":"Tông môn","diaBan":"Thiên Nam","nhanVatChinh":["Hoàn đạo hữu"],"blurb":"Tông môn Thiên Nam, Hoàn đạo hữu (Nguyên Anh tu sĩ) thuộc tông này vừa tử chiến trong chiến tranh Mộ Lan.","detail":"Ám Ảnh Tông có Nguyên Anh tu sĩ Hoàn đạo hữu, vị này tử chiến trong trận đại bại, là Nguyên Anh thứ hai chết trận kể từ khi khai chiến.","thanhVien":[{"ten":"Hoàn đạo hữu","chucVu":"Nguyên Anh tu sĩ","tuChuong":"@c0720","trangThai":"tu-vong"}],"tabs":{"tienTrinh":[{"chuong":"@c0720","loai":"nhan-toi","importance":"normal","giaiDoan":"Tổn thất Nguyên Anh tu sĩ","text":"Hoàn đạo hữu (Nguyên Anh tu sĩ) tử chiến, là vị Nguyên Anh thứ hai chết trận kể từ khi khai chiến với Mộ Lan.","anchor":"thậm chí Ám Ảnh Tông Hoàn đạo hữu còn tử chiến trong trận này"}]},"nguon":["@c0720"]},{"id":"thanh-hu-mon","name":"Thanh Hư Môn","cn":"","type":"tong-mon","typeLabel":"Tông môn","diaBan":"","nhanVatChinh":["Trùng Vân Tử"],"blurb":"Tông môn của Trùng Vân Tử, đệ tử có mặt trong lực lượng phòng thủ tại Hoàng Long Sơn.","detail":"Tông môn tu tiên, có đệ tử Trùng Vân Tử (Kết Đan kỳ) tham gia trấn thủ Hoàng Long Sơn chống pháp sĩ Mộ Lan.","nguon":["@c0726"]},{"id":"thien-thai-coc","name":"Thiên Thai Cốc","cn":"","type":"cu-diem","typeLabel":"Cứ điểm phòng thủ","diaBan":"Tuyến trước phòng thủ Thiên Nam","nhanVatChinh":["Bặc Vân Hạc"],"blurb":"Cứ điểm phòng thủ tuyến trước do Bặc Vân Hạc (Nguyên Anh Kỳ) chủ trì, đã bị đại quân Mộ Lan phá vỡ đại trận bằng thượng cổ cự thú mặc chiến giáp, thất thủ.","detail":"Thiên Thai Cốc là cứ điểm dựa vào đại trận phòng thủ, nhưng pháp sĩ Mộ Lan lần này mang theo thượng cổ cự thú da dày thịt béo mặc chiến giáp được gia trì cổ quái cấm pháp, một khi xông vào thì đại trận sớm muộn bị phá. Bặc Vân Hạc tuy Nguyên Anh Kỳ có thể đả thương cự thú nhưng bị hai Đại Thượng Sư liên thủ kìm chân. Tu sĩ sống sót rút về Hoàng Long Sơn.","trangThai":"thất thủ","lanhDaoHienThoi":"Bặc Vân Hạc","thanhVien":[{"ten":"Bặc Vân Hạc","chucVu":"Chủ trì","tuChuong":"@c0728","trangThai":"da-roi"}],"tabs":{"tienTrinh":[{"chuong":"@c0728","loai":"diet","importance":"major","giaiDoan":"Thất thủ trước đại quân Mộ Lan","trangThaiMoc":"thất thủ","text":"Đại trận bị thượng cổ cự thú mặc chiến giáp phá vỡ. Bặc Vân Hạc bị hai Đại Thượng Sư liên thủ kìm chân. Tu sĩ sống sót rút về Hoàng Long Sơn nhờ lão giả họ Mã tiếp ứng.","anchor":"Lục đạo hữu nơi này có viện quân của Mã đạo hữu thì hẳn là sẽ không giống như Thiên Thai Cốc dễ dàng mất như vậy"}]},"capNhatToi":"@c0728","nguon":["@c0728"]},{"id":"bai-hoa-bo","name":"Bái Hỏa Bộ","cn":"拜火部","type":"bo-lac","typeLabel":"Bộ lạc","diaBan":"Thuộc phe Mộ Lan pháp sĩ","nhanVatChinh":["Quật Diệu"],"blurb":"Bộ lạc thuộc phe Mộ Lan pháp sĩ, có Đại Thượng Sư Quật Diệu sở hữu Thiên Địa Hỏa Linh có thể biến hóa thành hỏa giao.","detail":"Quật Diệu xưng danh Đại Thượng Sư Bái Hỏa Bộ khi khiêu chiến. Đây là lần đầu tiên tiết lộ tên bộ lạc cụ thể trong phe Mộ Lan pháp sĩ. Chuyên về hỏa thuộc tính.","nguonGoc":"Thuộc phe Mộ Lan pháp sĩ","thanhVien":[{"ten":"Quật Diệu","chucVu":"Đại Thượng Sư","tuChuong":"@c0729","trangThai":"hoat-dong"}],"tabs":{"tienTrinh":[{"chuong":"@c0729","loai":"xuất hiện","importance":"normal","giaiDoan":"Quật Diệu xưng danh","text":"Quật Diệu xưng danh Đại Thượng Sư Bái Hỏa Bộ, lần đầu tiết lộ tên bộ lạc cụ thể trong phe Mộ Lan.","anchor":"Tại hạ Bái Hỏa Bộ Đại Thượng Sư Quật Diệu"}]},"nguon":["@c0729"]},{"id":"bang-dai-de-quoc","name":"Bàng Đại đế quốc","cn":"","type":"de-quoc","typeLabel":"Đế quốc","diaBan":"Bên kia thảo nguyên Mộ Lan","nhanVatChinh":["Hắc bào nhân"],"blurb":"Đế quốc nằm bên kia thảo nguyên Mộ Lan, nơi hắc bào nhân Thiên Khốc đến từ đó. Thiên Khốc đã đạt thỏa thuận với Thần Sư tam đại bộ lạc Mộ Lan.","detail":"Bàng Đại đế quốc nằm bên kia thảo nguyên Mộ Lan. Hắc bào nhân Thiên Khốc (Nguyên Anh kỳ) được xác nhận đến từ đế quốc này. Thiên Khốc sở hữu công pháp thần thông vượt xa tu sĩ cùng cấp Thiên Nam, đã tiêu diệt hai tu sĩ Nguyên Anh Thiên Nam trước đó. Hai Đại Thượng Sư Mộ Lan biết rõ bảy tám phần lai lịch, xác nhận Thiên Khốc đã đạt thỏa thuận với Thần Sư tam đại bộ lạc.","tabs":{"tienTrinh":[{"chuong":"@c0732","loai":"nhắc tới","importance":"normal","giaiDoan":"Lộ lai lịch Thiên Khốc","text":"Hắc bào nhân Thiên Khốc được xác nhận đến từ Bàng Đại đế quốc bên kia thảo nguyên Mộ Lan, đã đạt thỏa thuận với Thần Sư tam đại bộ lạc.","anchor":"Tu sĩ thần bí này là đến từ Bàng Đại đế quốc bên kia thảo nguyên Mộ Lan"}]},"nguon":["@c0732"]},{"id":"nguoi-dot-ngot","name":"Người Đột Ngột","cn":"突骨人","type":"faction","typeLabel":"Thế lực thảo nguyên","diaBan":"Thảo nguyên (bao gồm hơn nửa thảo nguyên Mộ Lan đã chiếm)","nhanVatChinh":[],"blurb":"Thế lực hùng mạnh trên thảo nguyên, đã đánh bại chủ lực Mộ Lan trong quyết chiến và chiếm hơn nửa thảo nguyên Mộ Lan, xưng bá thảo nguyên.","detail":"Người Đột Ngột là thế lực đối địch chính của người Mộ Lan trên thảo nguyên. Trong một trận quyết chiến, chủ lực Mộ Lan đại bại trước người Đột Ngột, dẫn đến hơn nửa thảo nguyên Mộ Lan bị chiếm cứ. Chính thất bại này khiến người Mộ Lan rơi vào tình cảnh tuyệt vọng, buộc phải liều lĩnh xâm lược Thiên Nam để chiếm đoạt tư nguyên tu luyện, với hy vọng tăng cường thực lực rồi quay lại đánh bại người Đột Ngột. Người Đột Ngột có các tiên sư mà Mộ Lan muốn đánh tan nhưng chưa đủ lực.","nguon":["@c0733"]}]};
